echo -e "\n=== Unit-тесты для QR-позиционирования ==="
./gradlew test --tests "*QrCodeDaoTest"

echo -e "\n=== Тесты шифрования базы данных ==="
./gradlew test --tests "*DatabaseEncryptionTest"

echo -e "\n=== Интеграционные тесты ==="
./gradlew connectedAndroidTest --tests "*MapScreenTest"

echo -e "\n=== Тесты сканирования QR-кодов ==="
