echo -e "\n=== Тесты обновления приложения ==="
./gradlew test --tests "*AppUpdateTest"

echo -e "\n=== Тесты обнаружения root-доступа ==="
./gradlew test --tests "*RootDetectionTest"

echo -e "\n=== Тесты доступа к квизу ==="
./gradlew test --tests "*QuizAccessTest"

echo -e "\n=== Проверка линтинга ==="
./gradlew ktlintCheck

echo -e "\n=== Проверка детекта ==="
./gradlew detekt

echo -e "\n=== Запуск всех тестов ==="
bash scripts/run_all_tests.sh

echo -e "\n=== Финальная проверка ==="
bash scripts/run_final_checks.sh

echo "Все проверки завершены!"
```

Теперь сделаем его исполняемым:

```bash
chmod +x scripts/run_all_checks.sh
```

