### Тест шифрования базы данных

Создадим файл `tests/database/test_database_encryption.kt`:

```kotlin
package com.safeplant.tests.database

import androidx.test.ext.junit.runners.AndroidJUnit4
import androidx.test.platform.app.InstrumentationRegistry
import com.safeplant.core.database.AppDatabase
import com.safeplant.core.database.dao.AccessPassDao
import com.safeplant.core.database.entity.AccessPass
import org.junit.After
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import java.io.IOException

@RunWith(AndroidJUnit4::class)
class DatabaseEncryptionTest {

    private lateinit var database: AppDatabase
    private lateinit var accessPassDao: AccessPassDao

    @Before
    fun setup() {
        val context = InstrumentationRegistry.getInstrumentation().targetContext
        database = AppDatabase.getDatabase(context)
        accessPassDao = database.accessPassDao()
    }

    @After
    fun tearDown() {
        database.close()
    }

    @Test
    @Throws(IOException::class)
    fun insertAndGetAccessPass() {
        val accessPass = AccessPass(
            userId = "test_user",
            issuedAt = System.currentTimeMillis(),
            expiryDate = System.currentTimeMillis() + (30 * 24 * 60 * 60 * 1000), // 30 дней
            isValid = true
        )

        val id = accessPassDao.insert(accessPass)
        assertTrue(id > 0)

        val retrievedPass = accessPassDao.getValidById(id, System.currentTimeMillis())
        assertEquals(accessPass.userId, retrievedPass?.userId)
        assertEquals(accessPass.issuedAt, retrievedPass?.issuedAt)
        assertEquals(accessPass.expiryDate, retrievedPass?.expiryDate)
        assertEquals(accessPass.isValid, retrievedPass?.isValid)
    }

    @Test
    @Throws(IOException::class)
    fun getValidAccessPass() {
        val currentTime = System.currentTimeMillis()
        val validPass = AccessPass(
            userId = "test_user",
            issuedAt = currentTime,
            expiryDate = currentTime + (30 * 24 * 60 * 60 * 1000), // 30 дней
            isValid = true
        )

        val expiredPass = AccessPass(
            userId = "test_user",
            issuedAt = currentTime - (40 * 24 * 60 * 60 * 1000), // 40 дней назад
            expiryDate = currentTime - (10 * 24 * 60 * 60 * 1000), // 10 дней назад
            isValid = false
        )

        accessPassDao.insert(validPass)
        accessPassDao.insert(expiredPass)

        val retrievedPass = accessPassDao.getValidAccessPass("test_user", currentTime)
        assertEquals(validPass.userId, retrievedPass?.userId)
        assertEquals(validPass.issuedAt, retrievedPass?.issuedAt)
        assertEquals(validPass.expiryDate, retrievedPass?.expiryDate)
        assertEquals(validPass.isValid, retrievedPass?.isValid)
    }

    @Test
    @Throws(IOException::class)
    fun hasValidAccessPass() {
        val currentTime = System.currentTimeMillis()
        val validPass = AccessPass(
            userId = "test_user",
            issuedAt = currentTime,
            expiryDate = currentTime + (30 * 24 * 60 * 60 * 1000), // 30 дней
            isValid = true
        )

        accessPassDao.insert(validPass)

        assertTrue(accessPassDao.hasValidAccessPass("test_user", currentTime))
        assertFalse(accessPassDao.hasValidAccessPass("nonexistent_user", currentTime))
    }
}
```

### Тест сканирования QR-кодов

Создадим файл `tests/database/test_qr_scan.kt`:

```kotlin
package com.safeplant.tests.database

import androidx.test.ext.junit.runners.AndroidJUnit4
import androidx.test.platform.app.InstrumentationRegistry
import com.safeplant.core.database.AppDatabase
import com.safeplant.core.database.dao.QrCodeDao
import com.safeplant.core.database.entity.QrCodeMapping
import org.junit.After
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNotNull
import org.junit.Assert.assertNull
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import java.io.IOException

@RunWith(AndroidJUnit4::class)
class QrCodeScanTest {

    private lateinit var database: AppDatabase
    private lateinit var qrCodeDao: QrCodeDao

    @Before
    fun setup() {
        val context = InstrumentationRegistry.getInstrumentation().targetContext
        database = AppDatabase.getDatabase(context)
        qrCodeDao = database.qrCodeDao()
    }

    @After
    fun tearDown() {
        database.close()
    }

    @Test
    @Throws(IOException::class)
    fun insertAndGetQrCodeMapping() {
        val mapping = QrCodeMapping(
            objectId = "123",
            name = "Цех А",
            latitude = 55.7558,
            longitude = 37.6173
        )

        val id = qrCodeDao.insert(mapping)
        assertTrue(id > 0)

        val retrievedMapping = qrCodeDao.getByObjectId("123")
        assertNotNull(retrievedMapping)
        assertEquals(mapping.objectId, retrievedMapping?.objectId)
        assertEquals(mapping.name, retrievedMapping?.name)
        assertEquals(mapping.latitude, retrievedMapping?.latitude, 0.001)
        assertEquals(mapping.longitude, retrievedMapping?.longitude, 0.001)
    }

    @Test
    @Throws(IOException::class)
    fun getNonExistentQrCodeMapping() {
        val retrievedMapping = qrCodeDao.getByObjectId("nonexistent_id")
        assertNull(retrievedMapping)
    }

    @Test
    @Throws(IOException::class)
    fun insertMultipleQrCodeMappings() {
        val mapping1 = QrCodeMapping(
            objectId = "123",
            name = "Цех А",
            latitude = 55.7558,
            longitude = 37.6173
        )

        val mapping2 = QrCodeMapping(
            objectId = "456",
            name = "Цех Б",
            latitude = 55.7568,
            longitude = 37.6183
        )

        qrCodeDao.insert(mapping1)
        qrCodeDao.insert(mapping2)

        val retrievedMapping1 = qrCodeDao.getByObjectId("123")
        val retrievedMapping2 = qrCodeDao.getByObjectId("456")

        assertNotNull(retrievedMapping1)
        assertNotNull(retrievedMapping2)

        assertEquals(mapping1.objectId, retrievedMapping1?.objectId)
        assertEquals(mapping2.objectId, retrievedMapping2?.objectId)
    }
}
```

### Тест обновления приложения

Создадим файл `tests/app/test_app_update.kt`:

```kotlin
package com.safeplant.tests.app

import androidx.test.ext.junit.runners.AndroidJUnit4
import androidx.test.platform.app.InstrumentationRegistry
import com.safeplant.core.database.AppDatabase
import com.safeplant.core.database.dao.AccessPassDao
import com.safeplant.core.database.entity.AccessPass
import com.safeplant.feature.profile.ProfileViewModel
import org.junit.After
import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import java.io.IOException

@RunWith(AndroidJUnit4::class)
class AppUpdateTest {

    private lateinit var database: AppDatabase
    private lateinit var accessPassDao: AccessPassDao
    private lateinit var profileViewModel: ProfileViewModel

    @Before
    fun setup() {
        val context = InstrumentationRegistry.getInstrumentation().targetContext
        database = AppDatabase.getDatabase(context)
        accessPassDao = database.accessPassDao()
        profileViewModel = ProfileViewModel(context as android.app.Application)
    }

    @After
    fun tearDown() {
        database.close()
    }

    @Test
    @Throws(IOException::class)
    fun shouldResetAccessPassesWhenVersionChanges() {
        // Создаем действующий допуск
        val currentTime = System.currentTimeMillis()
        val accessPass = AccessPass(
            userId = "test_user",
            issuedAt = currentTime,
            expiryDate = currentTime + (30 * 24 * 60 * 60 * 1000), // 30 дней
            isValid = true
        )

        accessPassDao.insert(accessPass)

        // Проверяем, что допуск существует
        assertTrue(accessPassDao.hasValidAccessPass("test_user", currentTime))

        // Проверяем, что при изменении версии допуск сбрасывается
        val currentVersion = "2.0.0"
        val storedVersion = "1.0.0"

        assertTrue(profileViewModel.shouldResetAccessPasses(currentVersion, storedVersion))

        // Сбрасываем допуски
        profileViewModel.resetAllAccessPasses()

        // Проверяем, что допуска больше нет
        assertFalse(accessPassDao.hasValidAccessPass("test_user", currentTime))
    }

    @Test
    @Throws(IOException::class)
    fun shouldNotResetAccessPassesWhenVersionSame() {
        // Создаем действующий допуск
        val currentTime = System.currentTimeMillis()
        val accessPass = AccessPass(
            userId = "test_user",
            issuedAt = currentTime,
            expiryDate = currentTime + (30 * 24 * 60 * 60 * 1000), // 30 дней
            isValid = true
        )

        accessPassDao.insert(accessPass)

        // Проверяем, что допуск существует
        assertTrue(accessPassDao.hasValidAccessPass("test_user", currentTime))

        // Проверяем, что при одинаковых версиях допуск не сбрасывается
        val currentVersion = "1.0.0"
        val storedVersion = "1.0.0"

        assertFalse(profileViewModel.shouldResetAccessPasses(currentVersion, storedVersion))
    }

    @Test
    @Throws(IOException::class)
    fun shouldNotResetAccessPassesWhenNoStoredVersion() {
        // Создаем действующий допуск
        val currentTime = System.currentTimeMillis()
        val accessPass = AccessPass(
            userId = "test_user",
            issuedAt = currentTime,
            expiryDate = currentTime + (30 * 24 * 60 * 60 * 1000), // 30 дней
            isValid = true
        )

        accessPassDao.insert(accessPass)

        // Проверяем, что допуск существует
        assertTrue(accessPassDao.hasValidAccessPass("test_user", currentTime))

        // Проверяем, что при отсутствии сохраненной версии допуск не сбрасывается
        val currentVersion = "1.0.0"
        val storedVersion: String? = null

        assertFalse(profileViewModel.shouldResetAccessPasses(currentVersion, storedVersion))
    }
}
```

